def solve(height_in_inches, sex, actual_weight_kg):
    # Step 1: Calculate ideal body weight (IBW) based on sex and height
    if sex.lower() == 'male':
        ibw = 50 + 2.3 * (height_in_inches - 60)
    elif sex.lower() == 'female':
        ibw = 45.5 + 2.3 * (height_in_inches - 60)
    else:
        raise ValueError("Sex must be 'male' or 'female'")

    yield {
        "step_name": "calculate_ibw",
        "step_description": "Calculate ideal body weight (IBW) based on sex and height. For males: IBW = 50 + 2.3 * (height_in_inches - 60). For females: IBW = 45.5 + 2.3 * (height_in_inches - 60).",
        "step_result": ibw,
        "unit": "kg"
    }

    # Step 2: Calculate adjusted body weight (ABW) using ABW = IBW + 0.4 * (actual_weight_kg - IBW)
    adjusted_body_weight = round(ibw + 0.4 * (actual_weight_kg - ibw), 4)

    yield {
        "step_name": "calculate_abw",
        "step_description": "Calculate adjusted body weight using ABW = IBW + 0.4 * (actual_weight_kg - IBW), rounded to 4 decimal places.",
        "step_result": adjusted_body_weight,
        "unit": "kg"
    }

    # Final output
    return adjusted_body_weight
